// вФАвФАвФА JSONмЧРмДЬ tool_response.stdout мґФмґЬ вФАвФАвФА
fn extract_stdout(json_text: string) -> string {
    // 'tool_response':{'stdout':'...' мЧРмДЬ stdout к∞Т мґФмґЬ
    if json_text.contains('\'stdout\':\'') {
        let parts = json_text.split('\'stdout\':\'')
        if parts.len() >= 2 {
            // мЭімК§мЉАмЭінФДлРЬ лФ∞мШінСЬл•Љ лДШк≤®мДЬ мІДмІЬ лЛЂлКФ лФ∞мШінСЬ м∞ЊкЄ∞
            let rest = parts[1]
            let mut result = ''
            let mut i = 0
            let chars = rest.split('')
            let mut prev_backslash = false
            while i < chars.len() {
                let c = chars[i]
                if c == '\\' && !prev_backslash {
                    prev_backslash = true
                    i = i + 1
                    continue
                }
                if c == '\'' && !prev_backslash {
                    return result
                }
                if prev_backslash {
                    if c == 'n' { result = result + '\n' }
                    else if c == 't' { result = result + '\t' }
                    else { result = result + c }
                    prev_backslash = false
                } else {
                    result = result + c
                }
                i = i + 1
            }
            return result
        }
    }
    // JSONмЭі мХДлЛИл©і мЫРл≥Є кЈЄлМАл°Ь (нММмЭінФД нЕМмК§нКЄ лУ±)
    json_text
}

// вФАвФАвФА tool_input.command мґФмґЬ (мЖМмК§ нСЬмЛЬмЪ©) вФАвФАвФА
fn extract_command(json_text: string) -> string {
    if json_text.contains('\'command\':\'') {
        let parts = json_text.split('\'command\':\'')
        if parts.len() >= 2 {
            let rest = parts[1]
            let end = rest.split('\'')[0]
            if end.len() > 40 { return end.split('')[0] + '...' }
            return end
        }
    }
    ''
}

// вФАвФАвФА CWDмЧРмДЬ нФДл°Ьм†ЭнКЄл™Е мґФмґЬ вФАвФАвФА
fn extract_project(json_text: string) -> string {
    if json_text.contains('\'cwd\':\'') {
        let parts = json_text.split('\'cwd\':\'')
        if parts.len() >= 2 {
