}','originalFile':'// вЫФ CORE вАФ L0 лґИл≥АмЛЭ (HEXA-GATE м†Д л¶ђнПђ нТИмІИ к≤МмЭінКЄ. мИШм†Х м†Д мЬ†м†А мКємЭЄ нХДмИШ)
// mk2_hexa/native/hook.hexa вАФ PostToolUse нЫЕ мЧФмІД (Python лМАм≤і)
// stdinмЬЉл°Ь JSON л∞ЫмХДмДЬ n6_match + mk2 classify вЖТ discovery_log кЄ∞л°Э
// мВђмЪ©: echo '$INPUT' | hexa hook.hexa post-edit

// log_pathлКФ _shared к≥ДмВ∞ нЫД лЯ∞нГАмЮДмЧР мД§м†Х (нГА нФДл°Ьм†ЭнКЄ CWD лМАмЭС)

pure fn abs_f(x: float) -> float {
    if x < 0.0 { 0.0 - x } else { x }
}

// вФАвФАвФА n6 мГБмИШ лПЩм†Б л°ЬлУЬ (shared/n6_constants.jsonl + n6_physics.jsonl) вФАвФАвФА
fn load_jsonl(path: string) -> list {
    let mut raw = ''
    try { raw = read_file(path) } catch e { return [[], []] }
    let lines = raw.split('\n')
    let mut names = []
    let mut values = []
    for line in lines {
        let trimmed = line.trim()
        if trimmed == '' { continue }
        let mut name = ''
        let mut value = 0.0
        if trimmed.contains('\'name\':\'') {
            let p = trimmed.split('\'name\':\'')
            if p.len() >= 2 { name = p[1].split('\'')[0] }
        }
        if trimmed.contains('\'value\':') {
            let p = trimmed.split('\'value\':')
            if p.len() >= 2 {
                let num_str = p[1].split(',')[0].split('}')[0].trim()
                value = to_float(num_str)
            }
        }
        if name != '' {
            names = names + [name]
            values = values + [value]
        }
    }
    [names, values]
}

let _home = exec('printenv HOME')
