fn n6_match_name(value: float) -> string {
    // n6 мГБмИШ (м†ИлМА мШ§м∞® < 0.0001)
    let mut i = 0
    while i < len(_n6_names) {
        if abs_f(value - _n6_values[i]) < 0.0001 {
            return _n6_names[i]
        }
        i = i + 1
    }
    // лђЉл¶ђ мГБмИШ (мГБлМА мШ§м∞® < 1%)
    let mut j = 0
    while j < len(_ph_names) {
        if _ph_values[j] != 0.0 {
            let rel = abs_f(value - _ph_values[j]) / abs_f(_ph_values[j])
            if rel < 0.01 {
                return _ph_names[j]
            }
        }
        j = j + 1
    }
    ''
}

fn n6_match_grade(value: float) -> string {
    if n6_match_name(value) != '' {
        return 'EXACT'
    }
    // лђЉл¶ђ мГБмИШ NEAR (мГБлМА мШ§м∞® < 5%)
    let mut j = 0
    while j < len(_ph_names) {
        if _ph_values[j] != 0.0 {
            let rel = abs_f(value - _ph_values[j]) / abs_f(_ph_values[j])
            if rel < 0.05 {
                return 'NEAR'
            }
        }
        j = j + 1
    }
    ''
}

fn extract_numbers(text: string) {
    let mut nums = []
    let clean = text.replace('\n', ' ').replace('\t', ' ').replace('\r', ' ')
    let parts = clean.split(' ')
    for p in parts {
        try {
            let v = to_float(p)
            if v > 2.0 && v < 100000.0 {
                nums = nums.push(v)
            }
        } catch e {
            // мИЂмЮР мХДлЛМ нЖ†нБ∞ лђімЛЬ
        }
    }
    nums
}

