fn fix_block_comments(source: string) {
    // /* ... */ м†Ьк±∞ (м§См≤© лѓЄмІАмЫР, лЛ®мИЬ нМ®нДі)
    let mut result = source
    let mut i = 0
    let mut out = ''
    let mut in_comment = false
    let mut depth = 0

    while i < len(result) {
        if i + 1 < len(result) {
            if result[i] == '/' && result[i + 1] == '*' {
                depth = depth + 1
                in_comment = true
                i = i + 2
                continue
            }
            if result[i] == '*' && result[i + 1] == '/' {
                depth = depth - 1
                if depth == 0 { in_comment = false }
                i = i + 2
                continue
            }
        }
        if !in_comment {
            out = out + result[i]
        }
        i = i + 1
    }
    return out
}

fn fix_semicolons(source: string) {
    // м§Д лБЭ мДЄлѓЄмљЬл°† м†Ьк±∞
    let lines = split(source, '\n')
    let mut fixed = []
    for line in lines {
        let trimmed = trim(line)
        if ends_with(trimmed, ';') {
            // for л£®нФД мХИмЭШ мДЄлѓЄмљЬл°†мЭА мЬ†мІА (C-style for)
            if !contains(line, 'for ') {
                let without = slice(trimmed, 0, len(trimmed) - 1)
                // мЫРл≥Є лУ§мЧђмУ∞кЄ∞ мЬ†мІА
                let indent = len(line) - len(trim_start(line))
                let spaces = repeat(' ', indent)
                fixed = push(fixed, spaces + without)
                continue
            }
        }
        fixed = push(fixed, line)
    }
    return join(fixed, '\n')
}

fn fix_array_type(source: string) {
