    if contains(source, '/*') { found = push(found, 'G3:block_comment') }
    if contains(source, '-> (') { found = push(found, 'G1:tuple_return') }

    let lines = split(source, '\n')
    for line in lines {
        let t = trim(line)
        if ends_with(t, ';') && !contains(t, 'for ') && !contains(t, '//') {
            found = push(found, 'G4:semicolon')
            break
